$Host.UI.RawUI.WindowTitle = "ScriptStudio AI Setup"
$ErrorActionPreference = "Continue"
[Console]::OutputEncoding = [System.Text.Encoding]::UTF8
chcp 65001 | Out-Null

Write-Host ""
Write-Host "=====================================================" -ForegroundColor Cyan
Write-Host "  ScriptStudio AI Setup" -ForegroundColor Cyan
Write-Host "  Installing: AI Model + Qwen3-TTS + ChatMock" -ForegroundColor Cyan
Write-Host "=====================================================" -ForegroundColor Cyan
Write-Host ""
Write-Host "Requirements:" -ForegroundColor Yellow
Write-Host "  - Internet connection"
Write-Host "  - NVIDIA GPU recommended"
Write-Host "  - ~15GB free disk space"
Write-Host ""
Read-Host "Press Enter to start"

# ── 드라이브 선택 ────────────────────────────────────────────
Write-Host ""
Write-Host "  Select installation drive:" -ForegroundColor Cyan
Write-Host "  [1] C drive (default)"
Write-Host "  [2] D drive"
Write-Host "  [3] Enter custom path"
$driveChoice = Read-Host "  Enter choice (1/2/3, default=1)"

switch ($driveChoice) {
    "2" { $installDrive = "D:" }
    "3" {
        $customPath = Read-Host "  Enter drive letter (e.g. E)"
        $installDrive = "${customPath}:"
    }
    default { $installDrive = "C:" }
}

$qwenDir   = "$installDrive\Qwen3-TTS"
$pythonDir = "$qwenDir\python-3.12-portable"
$pythonExe = "$pythonDir\python.exe"

Write-Host "  Installing to: $qwenDir" -ForegroundColor Green

# Qwen3-TTS 설치 위치를 qwen_config.json에 기록 (ScriptStudio가 자동으로 런처 경로를 찾기 위해)
$ssConfig = "$env:LOCALAPPDATA\Programs\ScriptStudio\resources\ScriptStudioServer\qwen_config.json"
if (Test-Path (Split-Path $ssConfig)) {
    $cfgObj = @{ qwen_bat_path = "$qwenDir\Run Qwen3 TTS.bat"; qwen_port = 7860 }
    $cfgObj | ConvertTo-Json | Set-Content -Path $ssConfig -Encoding UTF8
    Write-Host "  qwen_config.json 업데이트 완료." -ForegroundColor Green
}

# Windows Defender 예외 등록 (백그라운드)
$exclusionPaths = @($qwenDir, "$installDrive\ollama_models", "$installDrive\huggingface_cache")
$epJoined = $exclusionPaths -join '","'
Start-Process powershell.exe -ArgumentList "-NoProfile","-NonInteractive","-WindowStyle","Hidden","-Command","Add-MpPreference -ExclusionPath @(`"$epJoined`") -ErrorAction SilentlyContinue" -WindowStyle Hidden

[System.Environment]::SetEnvironmentVariable("OLLAMA_MODELS", "$installDrive\ollama_models", "User")
[System.Environment]::SetEnvironmentVariable("HF_HOME", "$installDrive\huggingface_cache", "User")
$env:OLLAMA_MODELS = "$installDrive\ollama_models"
$env:HF_HOME      = "$installDrive\huggingface_cache"

# ── STEP 0: Git ─────────────────────────────────────────────
Write-Host ""
Write-Host "[0/5] Checking Git..." -ForegroundColor Cyan

$gitExists = Get-Command git -ErrorAction SilentlyContinue
if ($gitExists) {
    Write-Host "  Git already installed." -ForegroundColor Green
} else {
    Write-Host "  Installing Git..."
    $winget = Get-Command winget -ErrorAction SilentlyContinue
    $gitInstalled = $false
    if ($winget) {
        winget install Git.Git --accept-source-agreements --accept-package-agreements --silent
        $gitInstalled = $null -ne (Get-Command git -ErrorAction SilentlyContinue)
    }
    if (-not $gitInstalled) {
        $gitExe = "$env:TEMP\GitSetup.exe"
        Invoke-WebRequest -Uri "https://github.com/git-for-windows/git/releases/download/v2.47.1.windows.1/Git-2.47.1-64-bit.exe" -OutFile $gitExe -UseBasicParsing
        Start-Process -FilePath $gitExe -ArgumentList "/VERYSILENT /NORESTART" -Wait
        Remove-Item $gitExe -ErrorAction SilentlyContinue
        $env:Path = [System.Environment]::GetEnvironmentVariable("Path","Machine") + ";" + [System.Environment]::GetEnvironmentVariable("Path","User")
    }
    Write-Host "  Git installed." -ForegroundColor Green
}

# ── STEP 1: Ollama + AI Model ────────────────────────────────
Write-Host ""
Write-Host "[1/5] Installing Ollama + AI Model..." -ForegroundColor Cyan

$ollamaExists = Get-Command ollama -ErrorAction SilentlyContinue
if ($ollamaExists) {
    Write-Host "  Ollama already installed." -ForegroundColor Green
} else {
    $winget = Get-Command winget -ErrorAction SilentlyContinue
    $installed = $false
    if ($winget) {
        Write-Host "  Trying winget..."
        winget install Ollama.Ollama --accept-source-agreements --accept-package-agreements --silent
        $installed = $null -ne (Get-Command ollama -ErrorAction SilentlyContinue)
    }
    if (-not $installed) {
        $ollamaPath = "$env:TEMP\OllamaSetup.exe"
        try {
            Invoke-WebRequest -Uri "https://ollama.com/download/OllamaSetup.exe" -OutFile $ollamaPath -UseBasicParsing
            Start-Process -FilePath $ollamaPath -ArgumentList "/S" -Wait
            Remove-Item $ollamaPath -ErrorAction SilentlyContinue
            Write-Host "  Ollama installed." -ForegroundColor Green
        } catch {
            Write-Host "  ERROR: Failed to download Ollama." -ForegroundColor Red
        }
    }
}

# GPU 감지 → 최적 모델 선택
$vramGB = 0; $gpuName = "Unknown"
$nvidiaSmiPaths = @("nvidia-smi", "C:\Windows\System32\nvidia-smi.exe", "C:\Program Files\NVIDIA Corporation\NVSMI\nvidia-smi.exe")
foreach ($nvPath in $nvidiaSmiPaths) {
    $nvExists = if ($nvPath -like "*\*") { Test-Path $nvPath } else { $null -ne (Get-Command $nvPath -ErrorAction SilentlyContinue) }
    if ($nvExists) {
        try {
            $nvidiaOut = & $nvPath --query-gpu=name,memory.total --format=csv,noheader,nounits 2>$null
            if ($nvidiaOut) {
                $parts = ($nvidiaOut.Trim() -split "`n")[0] -split ","
                $gpuName = $parts[0].Trim()
                $vramGB = [math]::Round([int]$parts[1].Trim() / 1024, 1)
                break
            }
        } catch {}
    }
}
if ($vramGB -eq 0) {
    $gpus = Get-CimInstance Win32_VideoController -ErrorAction SilentlyContinue
    foreach ($gpu in $gpus) {
        if ($gpu.Name -like "*NVIDIA*") {
            $gpuName = $gpu.Name; $ram = $gpu.AdapterRAM
            if ($ram -gt 0) {
                $vramGB = [math]::Round($ram / 1GB, 1)
                if ($vramGB -le 4) {
                    if ($gpuName -match "5090|4090|3090")      { $vramGB = 24 }
                    elseif ($gpuName -match "5080|4080|3080")  { $vramGB = 16 }
                    elseif ($gpuName -match "5070|4070")       { $vramGB = 12 }
                    elseif ($gpuName -match "5060 Ti|4060 Ti") { $vramGB = 8  }
                    elseif ($gpuName -match "5060|4060|3060")  { $vramGB = 8  }
                }
                break
            }
        }
    }
}
if     ($vramGB -ge 10.5) { $modelToPull = "deepseek-r1:14b"; $modelName = "DeepSeek-R1-14B" }
elseif ($vramGB -ge 7.5)  { $modelToPull = "qwen2.5:7b";      $modelName = "Qwen2.5-7B"      }
elseif ($vramGB -ge 5.5)  { $modelToPull = "qwen2.5:3b";      $modelName = "Qwen2.5-3B"      }
else                       { $modelToPull = "qwen2.5:1.5b";    $modelName = "Qwen2.5-1.5B"    }

Write-Host "  GPU: $gpuName (VRAM: $vramGB GB) → $modelName" -ForegroundColor Green
$ollamaExists = Get-Command ollama -ErrorAction SilentlyContinue
if ($ollamaExists) {
    Start-Process -FilePath "ollama" -ArgumentList "serve" -WindowStyle Hidden -ErrorAction SilentlyContinue
    Start-Sleep -Seconds 3
    & ollama pull $modelToPull
    if ($LASTEXITCODE -eq 0) { Write-Host "  Model ready." -ForegroundColor Green }
    else { Write-Host "  Model pull failed. Run 'ollama pull $modelToPull' manually." -ForegroundColor Yellow }
} else {
    Write-Host "  Ollama not found. Restart PC and run setup again." -ForegroundColor Red
}

# ── STEP 2: Qwen3-TTS (포터블 Python) ───────────────────────
Write-Host ""
Write-Host "[2/5] Installing Qwen3-TTS..." -ForegroundColor Cyan

if (Test-Path "$qwenDir\Run Qwen3 TTS.bat") {
    Write-Host "  Qwen3-TTS already installed." -ForegroundColor Green
} else {
    New-Item -ItemType Directory -Path $qwenDir -Force | Out-Null

    # Python 3.12 embeddable 다운로드
    Write-Host "  Downloading Python 3.12..."
    $pyZip = "$env:TEMP\python312.zip"
    try {
        Invoke-WebRequest -Uri "https://www.python.org/ftp/python/3.12.9/python-3.12.9-embed-amd64.zip" -OutFile $pyZip -UseBasicParsing
        Expand-Archive -Path $pyZip -DestinationPath $pythonDir -Force
        Remove-Item $pyZip -ErrorAction SilentlyContinue
        Add-Content -Path "$pythonDir\python312._pth" -Value "import site"
        Write-Host "  Python ready." -ForegroundColor Green
    } catch {
        Write-Host "  ERROR: Python download failed." -ForegroundColor Red
        Read-Host "Press Enter to close"; return
    }

    # pip 설치
    Write-Host "  Installing pip..."
    $getPip = "$env:TEMP\get-pip.py"
    Invoke-WebRequest -Uri "https://bootstrap.pypa.io/get-pip.py" -OutFile $getPip -UseBasicParsing
    & $pythonExe $getPip --no-warn-script-location -q
    Remove-Item $getPip -ErrorAction SilentlyContinue

    # qwen_app + qwen_tts + app.py (embedded bundle)
    Write-Host "  Installing Qwen app files (embedded)..." -ForegroundColor Yellow
    $zipDest = "$env:TEMP\qwen_bundle.zip"
    $b64Data = ""
    try {
        $zipBytes = [Convert]::FromBase64String($b64Data)
        [System.IO.File]::WriteAllBytes($zipDest, $zipBytes)
        Expand-Archive -Path $zipDest -DestinationPath $qwenDir -Force
        Remove-Item $zipDest -ErrorAction SilentlyContinue
        Write-Host "  Qwen app files installed." -ForegroundColor Green
    } catch {
        Write-Host "  ERROR: Failed to install Qwen app files: $_" -ForegroundColor Red
    }

    # 패키지 설치
    Write-Host "  Installing packages (5-10 min)..."
    Write-Host "  1/3: gradio, soundfile, numpy, scipy..."
    & $pythonExe -m pip install gradio gradio_client gradio_modal soundfile numpy scipy psutil -q --no-warn-script-location
    Write-Host "  2/3: PyTorch CUDA 12.8..."
    & $pythonExe -m pip install torch torchaudio --index-url https://download.pytorch.org/whl/cu128 -q --no-warn-script-location
    if ($LASTEXITCODE -ne 0) {
        Write-Host "  CUDA 12.8 failed. Trying CUDA 12.1..."
        & $pythonExe -m pip install torch torchaudio --index-url https://download.pytorch.org/whl/cu121 -q --no-warn-script-location
    }
    Write-Host "  3/3: transformers, accelerate, librosa, huggingface_hub..."
    & $pythonExe -m pip install transformers accelerate librosa huggingface_hub -q --no-warn-script-location

    # 런처 생성
    $ssRes = "$env:LOCALAPPDATA\Programs\ScriptStudio\resources\ScriptStudioServer"
    $launcher = @"
@echo off
echo Starting Qwen3 TTS...
set PYTHON_DIR=%~dp0python-3.12-portable
set SCRIPTSTUDIO_RES=$ssRes
set PYTHONPATH=%~dp0;%SCRIPTSTUDIO_RES%;%PYTHONPATH%
set HF_HUB_DISABLE_SYMLINKS_WARNING=1
set HF_HOME=$installDrive\huggingface_cache
set QWEN_POOL_SIZE=1
set QWEN_PRELOAD=Base:1.7B
set QWEN_USE_FASTER_BACKEND=0
"%PYTHON_DIR%\python.exe" "%~dp0app.py"
pause
"@
    [System.IO.File]::WriteAllText("$qwenDir\Run Qwen3 TTS.bat", $launcher, [System.Text.Encoding]::ASCII)
    Write-Host "  Qwen3-TTS installed." -ForegroundColor Green
    Write-Host "  NOTE: AI model (~3GB) downloads automatically on first use." -ForegroundColor Yellow
}

# ── STEP 3: ScriptStudioServer ──────────────────────────────
Write-Host ""
Write-Host "[3/5] Installing ScriptStudio Server..." -ForegroundColor Cyan

$serverInstallDir = "$env:LOCALAPPDATA\Programs\ScriptStudio\resources\ScriptStudioServer"
$serverExe        = "$serverInstallDir\ScriptStudioServer.exe"
$bundledServer    = "$PSScriptRoot\ScriptStudioServer"

if (Test-Path $bundledServer) {
    New-Item -ItemType Directory -Path $serverInstallDir -Force | Out-Null
    Write-Host "  Copying ScriptStudioServer..."
    Copy-Item "$bundledServer\*" $serverInstallDir -Recurse -Force
    Write-Host "  ScriptStudioServer installed." -ForegroundColor Green
} else {
    Write-Host "  ScriptStudioServer bundle not found — skipping." -ForegroundColor Yellow
}

# qwen_config.json 저장 (서버 디렉토리가 확보된 이후)
if (Test-Path $serverInstallDir) {
    $cfgObj = @{ qwen_bat_path = "$qwenDir\Run Qwen3 TTS.bat"; qwen_port = 7860 }
    $cfgObj | ConvertTo-Json | Set-Content -Path "$serverInstallDir\qwen_config.json" -Encoding UTF8
    Write-Host "  qwen_config.json updated." -ForegroundColor Green
}

# 통합 런처 생성 (ScriptStudioServer + Qwen3-TTS 동시 시작)
$launcherPath = "$env:USERPROFILE\Desktop\ScriptStudio_Run.bat"
$launcherContent = @"
@echo off
title ScriptStudio Server Launcher
echo Starting ScriptStudio servers...
if exist "$serverExe" (
    start "" /B "$serverExe"
    echo ScriptStudioServer started ^(port 8000^)
) else (
    echo WARNING: ScriptStudioServer.exe not found
)
if exist "$qwenDir\Run Qwen3 TTS.bat" (
    start "" "$qwenDir\Run Qwen3 TTS.bat"
    echo Qwen3-TTS starting ^(port 7860^)
) else (
    echo WARNING: Qwen3-TTS not found
)
echo.
echo Servers starting. Open ScriptStudio in your browser after 30 seconds.
timeout /t 5
"@
[System.IO.File]::WriteAllText($launcherPath, $launcherContent, [System.Text.Encoding]::ASCII)
Write-Host "  Launcher created on Desktop: ScriptStudio_Run.bat" -ForegroundColor Green

# Windows 시작프로그램 등록 → 로그인할 때 자동 실행
$startupBat = "$env:APPDATA\Microsoft\Windows\Start Menu\Programs\Startup\ScriptStudio Servers.bat"
Copy-Item $launcherPath $startupBat -Force
Write-Host "  Registered in Windows startup (auto-start on login)." -ForegroundColor Green

# ── STEP 4: ChatMock (ChatGPT Login) ────────────────────────
Write-Host ""
Write-Host "[4/5] Configuring ChatMock..." -ForegroundColor Cyan

if (-not (Test-Path $pythonExe)) {
    Write-Host "  ERROR: Portable Python not found. Cannot install ChatMock." -ForegroundColor Red
} else {
    if (Test-Path "$pythonDir\Scripts\chatmock.exe") {
        Write-Host "  ChatMock already installed." -ForegroundColor Green
    } else {
        Write-Host "  Installing ChatMock..."
        & $pythonExe -m pip install chatmock -q --no-warn-script-location
        if ($LASTEXITCODE -eq 0) { Write-Host "  ChatMock installed." -ForegroundColor Green }
        else { Write-Host "  ERROR: ChatMock install failed." -ForegroundColor Red }
    }
    $scriptsPath = "$pythonDir\Scripts"
    if (Test-Path $scriptsPath) {
        $currentPath = [System.Environment]::GetEnvironmentVariable("Path", "User")
        if ($currentPath -notlike "*$scriptsPath*") {
            [System.Environment]::SetEnvironmentVariable("Path", $currentPath + ";$scriptsPath", "User")
            $env:Path += ";$scriptsPath"
            Write-Host "  PATH updated." -ForegroundColor Green
        }
    }
}

# ── STEP 4: ffmpeg ──────────────────────────────────────────
Write-Host ""
Write-Host "[5/5] Checking ffmpeg..." -ForegroundColor Cyan

$ffmpegExists = Get-Command ffmpeg -ErrorAction SilentlyContinue
if ($ffmpegExists) {
    Write-Host "  ffmpeg already installed." -ForegroundColor Green
} else {
    $ffmpegDir = "$installDrive\ffmpeg"
    $ffmpegBin = "$ffmpegDir\bin"
    $bundledCandidates = @(
        "$env:LOCALAPPDATA\Programs\ScriptStudio\resources\ScriptStudioServer\_internal\ffmpeg.exe",
        "$env:ProgramFiles\ScriptStudio\resources\ScriptStudioServer\_internal\ffmpeg.exe"
    )
    $used = $false
    foreach ($candidate in $bundledCandidates) {
        if (Test-Path $candidate) {
            New-Item -ItemType Directory -Path $ffmpegBin -Force | Out-Null
            Copy-Item $candidate $ffmpegBin -Force
            $currentPath = [System.Environment]::GetEnvironmentVariable("Path", "User")
            if ($currentPath -notlike "*$ffmpegBin*") {
                [System.Environment]::SetEnvironmentVariable("Path", $currentPath + ";$ffmpegBin", "User")
                $env:Path += ";$ffmpegBin"
            }
            Write-Host "  ffmpeg ready (bundled)." -ForegroundColor Green
            $used = $true; break
        }
    }
    if (-not $used) {
        try {
            Write-Host "  Downloading ffmpeg..."
            $ffmpegZip = "$env:TEMP\ffmpeg.zip"
            Invoke-WebRequest -Uri "https://www.gyan.dev/ffmpeg/builds/ffmpeg-release-essentials.zip" -OutFile $ffmpegZip -UseBasicParsing -TimeoutSec 120
            Expand-Archive -Path $ffmpegZip -DestinationPath "$installDrive\" -Force
            $extracted = Get-ChildItem "$installDrive\" -Directory | Where-Object { $_.Name -like "ffmpeg*" } | Select-Object -First 1
            if ($extracted) {
                if (Test-Path $ffmpegDir) { Remove-Item $ffmpegDir -Recurse -Force }
                Rename-Item $extracted.FullName $ffmpegDir
            }
            Remove-Item $ffmpegZip -ErrorAction SilentlyContinue
            $currentPath = [System.Environment]::GetEnvironmentVariable("Path", "Machine")
            if ($currentPath -notlike "*$ffmpegBin*") {
                [System.Environment]::SetEnvironmentVariable("Path", $currentPath + ";$ffmpegBin", "Machine")
                $env:Path += ";$ffmpegBin"
            }
            Write-Host "  ffmpeg installed." -ForegroundColor Green
        } catch {
            Write-Host "  ERROR: ffmpeg download failed. Install manually: https://ffmpeg.org" -ForegroundColor Red
        }
    }
}

# ── 완료 ───────────────────────────────────────────────────
Write-Host ""
Write-Host "=====================================================" -ForegroundColor Green
Write-Host "  Installation Complete!" -ForegroundColor Green
Write-Host "=====================================================" -ForegroundColor Green
Write-Host ""
Write-Host "  AI Model  : $modelName ready" -ForegroundColor White
Write-Host "  Qwen3-TTS : $qwenDir\Run Qwen3 TTS.bat" -ForegroundColor White
Write-Host "              (AI model ~3GB downloads on first voice use)" -ForegroundColor Gray
Write-Host "  ChatMock  : ChatGPT Login integration ready" -ForegroundColor White
Write-Host ""
Write-Host "  Launcher   : Desktop 'ScriptStudio_Run.bat'" -ForegroundColor White
Write-Host "               (auto-start after PC restart)" -ForegroundColor Gray
Write-Host "  Launch ScriptStudio now!" -ForegroundColor Cyan
Write-Host ""
Read-Host "Press Enter to close"
